/* Minimal lucide shim for Silvertech: implements createIcons for a small set of icons used in the site.
   This avoids external CDN dependency and provides lightweight inline SVG icons.
*/
(function(){
  function createSVG(name){
    const ns = 'http://www.w3.org/2000/svg';
    const svg = document.createElementNS(ns,'svg');
    svg.setAttribute('viewBox','0 0 24 24');
    svg.setAttribute('width','1em');
    svg.setAttribute('height','1em');
    svg.setAttribute('fill','none');
    svg.setAttribute('stroke','currentColor');
    svg.setAttribute('stroke-width','1.8');
    svg.setAttribute('stroke-linecap','round');
    svg.setAttribute('stroke-linejoin','round');

    function path(d){ const p = document.createElementNS(ns,'path'); p.setAttribute('d',d); return p }
    function circle(cx,cy,r){ const c = document.createElementNS(ns,'circle'); c.setAttribute('cx',cx); c.setAttribute('cy',cy); c.setAttribute('r',r); return c }

    switch(name){
      case 'shield':
        svg.appendChild(path('M12 3 5 6v5c0 4.2 2.8 7.8 7 9 4.2-1.2 7-4.8 7-9V6l-7-3Z'));
        svg.appendChild(path('m9.5 12 1.8 1.8 3.2-3.6'));
        break;
      case 'database':
        svg.appendChild(path('M4 7h16'));
        svg.appendChild(path('M7 7V5h10v2'));
        svg.appendChild(path('M6 7v10a2 2 0 0 0 2 2h8a2 2 0 0 0 2-2V7'));
        svg.appendChild(path('M9 11h6'));
        svg.appendChild(path('M9 15h4'));
        break;
      case 'shopping-bag':
      case 'shopping-bag-2':
        svg.appendChild(circle('8','20','1.5'));
        svg.appendChild(circle('18','20','1.5'));
        svg.appendChild(path('M2 4h2l2.2 9.2a1 1 0 0 0 1 .8h8.8a1 1 0 0 0 1-.8L16.5 8H6'));
        break;
      case 'home':
        svg.appendChild(path('M3 11.5 12 4l9 7.5V20a1 1 0 0 1-1 1h-5v-6H9v6H4a1 1 0 0 1-1-1z'));
        break;
      case 'cart':
        svg.appendChild(circle('8','20','1.5'));
        svg.appendChild(circle('18','20','1.5'));
        svg.appendChild(path('M2 4h2l2.2 9.2a1 1 0 0 0 1 .8h8.8a1 1 0 0 0 1-.8L16.5 8H6'));
        break;
      case 'mobile':
        svg.appendChild(path('M7 2h10a1 1 0 0 1 1 1v18a1 1 0 0 1-1 1H7a1 1 0 0 1-1-1V3a1 1 0 0 1 1-1z'));
        svg.appendChild(path('M12 18h.01'));
        break;
      default:
        // fallback: small circle
        svg.appendChild(circle('12','12','2'));
        break;
    }
    return svg;
  }

  window.lucide = window.lucide || {};
  window.lucide.createIcons = function(){
    document.querySelectorAll('[data-lucide]').forEach(function(el){
      try{
        const name = el.getAttribute('data-lucide') || el.textContent.trim();
        const svg = createSVG(name);
        // clear and insert svg
        while(el.firstChild) el.removeChild(el.firstChild);
        el.appendChild(svg);
      }catch(e){
        // fallback to text
        el.textContent = el.getAttribute('data-lucide') || '•';
      }
    });
  };
})();
